module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

reg [15:0] dividend;
reg [7:0] divisor;

always @(*) begin
    dividend = A;
    divisor = B;
    if (divisor == 0) begin
        result = 16'b0;
        odd = A;
    end
    else begin
        result = dividend / divisor;
        odd = dividend % divisor;
    end
end

endmodule
